import{_ as s,o,c as e,ae as l}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"飞书机器人 (急救龙虾) 注册与配置全通关指南（图文保姆级）","description":"","frontmatter":{},"headers":[],"relativePath":"tools/feishu-bot-setup.md","filePath":"tools/feishu-bot-setup.md"}'),t={name:"tools/feishu-bot-setup.md"};function r(a,i,n,p,g,h){return o(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="飞书机器人-急救龙虾-注册与配置全通关指南-图文保姆级" tabindex="-1">飞书机器人 (急救龙虾) 注册与配置全通关指南（图文保姆级） <a class="header-anchor" href="#飞书机器人-急救龙虾-注册与配置全通关指南-图文保姆级" aria-label="Permalink to &quot;飞书机器人 (急救龙虾) 注册与配置全通关指南（图文保姆级）&quot;">​</a></h1><p>这份指南将手把手、图文并茂地教你如何从零开始注册飞书，并配置一个专属的「急救龙虾」机器人。全程免费，不需要你懂代码，也不需要公网 IP！</p><hr><h2 id="第一步-注册飞书与创建企业" tabindex="-1">第一步：注册飞书与创建企业 <a class="header-anchor" href="#第一步-注册飞书与创建企业" aria-label="Permalink to &quot;第一步：注册飞书与创建企业&quot;">​</a></h2><ol><li><strong>打开官网</strong>：首先在浏览器打开 <a href="https://www.feishu.cn/" target="_blank" rel="noreferrer">飞书官网</a>。</li><li><strong>手机号登录</strong>：点击右上角的“登录”，直接用你的手机号接收验证码登录。</li><li><strong>创建企业</strong>： <ul><li>登录后，系统会问你是加入现有企业还是创建新企业。</li><li>请点击 <strong>“创建企业”</strong>。</li><li><strong>企业名称</strong>随便填（比如：龙虾极客工作室），行业和规模随便选（比如：IT / 1-10人）。</li><li>飞书的基础版是永久免费的，放心创建。</li></ul></li></ol><blockquote><p>💡 <strong>提示：</strong> 如果你已经有飞书企业了，这步可以直接跳过。</p></blockquote><p><em>(👇 请在此处替换为：创建企业页面截图)</em></p><hr><h2 id="第二步-在开放平台创建你的-机器人应用" tabindex="-1">第二步：在开放平台创建你的“机器人应用” <a class="header-anchor" href="#第二步-在开放平台创建你的-机器人应用" aria-label="Permalink to &quot;第二步：在开放平台创建你的“机器人应用”&quot;">​</a></h2><ol><li><strong>进入开发者后台</strong>：在浏览器新开一个标签页，打开 <a href="https://open.feishu.cn/app" target="_blank" rel="noreferrer">飞书开放平台后台 (open.feishu.cn/app)</a>。</li><li><strong>创建自建应用</strong>： <ul><li>在页面左侧，点击 <strong>「创建企业自建应用」</strong> 这个大按钮。</li></ul></li><li><strong>填写应用信息</strong>： <ul><li><strong>应用名称</strong>：写上「急救龙虾」或者你想取的名字。</li><li><strong>应用描述</strong>：填“我的私人 AI 助理”。</li><li><strong>应用图标</strong>：上传一张你喜欢的图片作为机器人的头像。</li><li>点击右下角的 <strong>「创建」</strong> 按钮。</li></ul></li></ol><p><em>(👇 请在此处替换为：填写应用信息截图)</em></p><hr><h2 id="第三步-给应用添加-机器人-灵魂" tabindex="-1">第三步：给应用添加“机器人”灵魂 <a class="header-anchor" href="#第三步-给应用添加-机器人-灵魂" aria-label="Permalink to &quot;第三步：给应用添加“机器人”灵魂&quot;">​</a></h2><p>刚创建好的应用只是个空壳，我们需要赋予它接收和发送消息的能力。</p><ol><li>在应用的管理后台，看 <strong>左侧菜单栏</strong>。</li><li>点击 <strong>「添加应用能力」</strong>。</li><li>在右侧出现的列表中，找到 <strong>「机器人」</strong>，然后点击它下面的 <strong>「添加」</strong> 按钮。</li></ol><p><em>(👇 请在此处替换为：添加机器人能力截图)</em></p><hr><h2 id="第四步-配置核心权限-🔥极易踩坑-必看" tabindex="-1">第四步：配置核心权限（🔥极易踩坑，必看！） <a class="header-anchor" href="#第四步-配置核心权限-🔥极易踩坑-必看" aria-label="Permalink to &quot;第四步：配置核心权限（🔥极易踩坑，必看！）&quot;">​</a></h2><p>机器人要能看懂你发的消息、能给你发图片，必须要有相应的“权限”。</p><ol><li><p>看左侧菜单栏，点击 <strong>「权限管理」</strong>。</p></li><li><p>在页面的搜索框里，依次搜索并<strong>打上勾</strong>。对于日常手机聊天、群组互动以及文档处理，<strong>以下是核心必开权限（缺一不可）</strong>：</p><p><strong>【核心聊天能力】</strong></p><ul><li><code>im:message:send_as_bot</code>（获取单聊、群组消息 —— <strong>最重要，必须开！</strong>）</li><li><code>im:message.p2p_msg:readonly</code>（接收单聊消息）</li><li><code>im:message.group_at_msg:readonly</code>（接收群聊中@我的消息）</li><li><code>im:message:readonly</code>（获取消息内容）</li><li><code>im:message</code>（获取和发送单聊、群组消息）</li><li><code>im:resource</code>（获取消息中的图片、文件）</li></ul><p><strong>【如果你需要在群里拉它】</strong></p><ul><li><code>im:chat</code>（获取和更新群组信息）</li><li><code>im:chat:read</code>（读取群组信息）</li></ul><p><strong>【如果你需要让它处理云文档（可选）】</strong></p><ul><li><code>docx:document</code>（读写文档）</li><li><code>drive:drive</code>（云盘文件读写）</li></ul></li></ol><p>⚠️ <strong>【超级避坑提示】</strong>：勾选完之后，这里只是暂存，<strong>必须通过第六步的“发布新版本”才会真正生效</strong>！新手最容易卡在这里。</p><p><em>(👇 请在此处替换为：勾选权限截图)</em></p><hr><h2 id="第五步-开启-websocket-长连接-免公网-ip-的秘密" tabindex="-1">第五步：开启 WebSocket 长连接（免公网 IP 的秘密） <a class="header-anchor" href="#第五步-开启-websocket-长连接-免公网-ip-的秘密" aria-label="Permalink to &quot;第五步：开启 WebSocket 长连接（免公网 IP 的秘密）&quot;">​</a></h2><p>为了让机器人能秒回你的消息，而且不需要你去搞复杂的公网 IP 和域名穿透，我们需要开启 WebSocket 模式。</p><ol><li>看左侧菜单栏，点击 <strong>「事件与回调」</strong>。</li><li>在页面上方，找到“回调方式”，把它切换到 <strong>「WebSocket 长连接」</strong>（注意：千万不要选 Webhook）。</li><li>接着在同一个页面，点击 <strong>「添加事件」</strong>。</li><li>搜索 <code>im.message.receive_v1</code>，勾选它（中文名叫：接收消息 v1.0）。</li></ol><p><em>(👇 请在此处替换为：WebSocket 和 事件配置截图)</em></p><hr><h2 id="第六步-发布应用-让一切配置生效" tabindex="-1">第六步：发布应用（让一切配置生效） <a class="header-anchor" href="#第六步-发布应用-让一切配置生效" aria-label="Permalink to &quot;第六步：发布应用（让一切配置生效）&quot;">​</a></h2><p>刚才配的权限和长连接，如果不发布，机器人就还是个“聋子”和“哑巴”。</p><ol><li>左侧菜单栏，向下滚动找到 <strong>「应用发布」</strong>，点击 <strong>「版本管理与发布」</strong>。</li><li>点击右上角的 <strong>「创建版本」</strong> 按钮。</li><li><strong>应用版本号</strong>：随便填，比如填 <code>1.0.0</code>。</li><li><strong>更新说明</strong>：随便填，比如填 <code>初始发布</code>。</li><li><strong>可用范围</strong>：选择你自己的名字，或者直接选“全部成员”。</li><li>点击最下方的 <strong>「保存并申请发布」</strong>。</li><li>因为你就是这个企业的超级管理员，系统会直接提示你审核通过，状态变为 <strong>已上架</strong>。</li></ol><p><em>(👇 请在此处替换为：版本发布截图)</em></p><hr><h2 id="第七步-拿到机器人的-身份证-并启动配置" tabindex="-1">第七步：拿到机器人的“身份证”并启动配置 <a class="header-anchor" href="#第七步-拿到机器人的-身份证-并启动配置" aria-label="Permalink to &quot;第七步：拿到机器人的“身份证”并启动配置&quot;">​</a></h2><ol><li>左侧菜单栏回到最上面，点击 <strong>「凭证与基础信息」</strong>。</li><li>在页面中间，你会看到两个很重要的东西，点击它们旁边的小眼睛显示出来： <ul><li><strong>App ID</strong> (类似账号，一般是 <code>cli_</code> 开头)</li><li><strong>App Secret</strong> (类似密码，很长一串)</li></ul></li><li>把这两串字符复制下来。</li><li>填入到你的 OpenClaw (或其他 AI 框架) 的配置文件中：</li></ol><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  feishu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    appId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;把你的App ID粘贴到这里&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    appSecret</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;把你的App Secret粘贴到这里&quot;</span></span></code></pre></div><p><em>(👇 请在此处替换为：获取凭证截图)</em></p><hr><h2 id="最后-去飞书找它聊天" tabindex="-1">最后：去飞书找它聊天！ <a class="header-anchor" href="#最后-去飞书找它聊天" aria-label="Permalink to &quot;最后：去飞书找它聊天！&quot;">​</a></h2><ol><li>打开你手机或电脑上的 <strong>飞书客户端</strong>。</li><li>在最上面的搜索框里，搜索「急救龙虾」（或者你起的名字）。</li><li>看到它的头像，点进去，你就可以直接和它聊天了！</li><li><strong>进阶玩法</strong>：你还可以建一个群，在群设置 -&gt; 群机器人 里把它拉进去，以后在群里 <code>@急救龙虾</code> 它就会在群里回复你了。</li></ol>`,40)])])}const u=s(t,[["render",r]]);export{c as __pageData,u as default};
